if (session_status() === PHP_SESSION_NONE) session_start();
require_once __DIR__ . '/../../../lessons/core/db.php';
if (!function_exists('get_pdo')) die('Error: get_pdo() was not found.');
function qz_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function qz_json($v){if($v===null||$v==='')return[];if(is_array($v))return$v;$d=json_decode((string)$v,true);return is_array($d)?$d:[];}
function qz_norm($v){return strtolower(trim(preg_replace('/\s+/',' ',(string)$v)));}
function qz_pick($r,$keys,$def=''){foreach($keys as $k){if(isset($r[$k])&&trim((string)$r[$k])!=='')return$r[$k];}return$def;}
function qz_redirect($m,$u,$a,$q=null,$x=[]){$url='?mode='.urlencode($m).'&unit='.intval($u).'&assignment='.intval($a);if($q!==null)$url.='&q='.intval($q);foreach($x as$k=>$v)$url.='&'.urlencode($k).'='.urlencode((string)$v);header('Location: '.$url);exit;}
function qz_rows_from_data($data){$p=qz_json($data);$rows=[];if(!$p)return$rows;if(isset($p[0])&&is_array($p[0]))$rows=$p;foreach(['questions','items','data','words','sentences','pairs','lines']as$k){if(isset($p[$k])&&is_array($p[$k])){$rows=$p[$k];break;}}if(empty($rows)&&is_array($p))$rows=[$p];return$rows;}
function qz_is_scoreable_type($type){return in_array($type,['quiz','multiple_choice','video_comprehension','fillblank','fill_blank','fill_in_blank','writing_practice','question_answer','matching_lines','match','dictation','pronunciation','order_sentences','unscramble','listen_order','drag_drop','drag_drop_kids'],true);}
function qz_add_mc(&$out,$id,$question,$options,$correct,$image=''){$options=array_values(array_filter($options,fn($v)=>trim((string)$v)!==''));if(trim((string)$question)!==''&&count($options)>=2)$out[]=['id'=>$id,'type'=>'multiple_choice','question'=>$question,'options'=>$options,'correct'=>$correct,'audio'=>'','image'=>$image,'pairs'=>[]];}
function qz_add_fill(&$out,$id,$question,$answer){if(trim((string)$question)!==''&&trim((string)$answer)!=='')$out[]=['id'=>$id,'type'=>'fill','question'=>$question,'options'=>[],'correct'=>$answer,'audio'=>'','image'=>'','pairs'=>[]];}
function qz_add_match(&$out,$id,$pairs,$question='Match each item with the correct option.'){$clean=[];foreach($pairs as$p){if(!is_array($p))continue;$l=qz_pick($p,['left','term','word','en','front','question','a','from']);$r=qz_pick($p,['right','match','translation','es','back','answer','b','to']);if($l!==''&&$r!=='')$clean[]=['left'=>$l,'right'=>$r];}if(count($clean)>=2)$out[]=['id'=>$id,'type'=>'match','question'=>$question,'options'=>[],'correct'=>'','audio'=>'','image'=>'','pairs'=>$clean];}
function qz_add_pron(&$out,$id,$row){$word=qz_pick($row,['en','word','text','phrase','prompt','question']);$img=qz_pick($row,['img','image','image_url']);$audio=qz_pick($row,['audio','audio_url']);$ph=qz_pick($row,['ph','phonetic']);if($word!=='')$out[]=['id'=>$id,'type'=>'pronunciation','question'=>$word,'options'=>[],'correct'=>$word,'audio'=>$audio,'image'=>$img,'ph'=>$ph,'pairs'=>[]];}
function qz_normalize_activity($act){$rawType=strtolower(trim((string)($act['type']??'')));if(!qz_is_scoreable_type($rawType))return[];$rows=qz_rows_from_data($act['data']??null);$out=[];$base=(string)($act['id']??uniqid('qz_',true)); if($rawType==='quiz'||$rawType==='multiple_choice'||$rawType==='video_comprehension'){foreach($rows as$i=>$r){if(!is_array($r))continue;$opts=isset($r['options'])&&is_array($r['options'])?$r['options']:(isset($r['choices'])&&is_array($r['choices'])?$r['choices']:[$r['option_a']??'',$r['option_b']??'',$r['option_c']??'',$r['option_d']??'']);qz_add_mc($out,$base.'_'.$i,qz_pick($r,['question','prompt','text','title']),$opts,qz_pick($r,['correct','correct_answer','answer','expected'],0),qz_pick($r,['img','image','image_url']));}} elseif($rawType==='fillblank'||$rawType==='fill_blank'||$rawType==='fill_in_blank'||$rawType==='writing_practice'||$rawType==='question_answer'){foreach($rows as$i=>$r){if(!is_array($r))continue;qz_add_fill($out,$base.'_'.$i,qz_pick($r,['question','prompt','sentence','text','en']),qz_pick($r,['answer','correct','correct_answer','expected','es']));}} elseif($rawType==='matching_lines'||$rawType==='match'||$rawType==='listen_order'||$rawType==='drag_drop'||$rawType==='drag_drop_kids'){qz_add_match($out,$base.'_m',$rows,'Match each item with its correct pair.');} elseif($rawType==='pronunciation'){foreach($rows as$i=>$r)if(is_array($r))qz_add_pron($out,$base.'_'.$i,$r);} elseif($rawType==='order_sentences'||$rawType==='unscramble'){foreach($rows as$i=>$r){if(!is_array($r))continue;$sentence=qz_pick($r,['sentence','text','en','answer','correct']);if($sentence!=='')$out[]=['id'=>$base.'_'.$i,'type'=>'unscramble','question'=>'Write the sentence in the correct order.','options'=>[],'correct'=>$sentence,'audio'=>'','image'=>'','pairs'=>[]];}} return$out;}
function qz_seed($u,$a,$att){$k='qz_seed_'.md5($u.'_'.$a.'_'.$att);if(!isset($_SESSION[$k]))$_SESSION[$k]=random_int(100000,999999);return(int)$_SESSION[$k];}
function qz_shuffle(&$arr,$seed){mt_srand($seed);for($i=count($arr)-1;$i>0;$i--){$j=mt_rand(0,$i);[$arr[$i],$arr[$j]]=[$arr[$j],$arr[$i]];}mt_srand();}
function qz_build($all,$u,$a,$att){$order=['pronunciation','multiple_choice','drag_drop','match','unscramble','fill'];$alias=['drag_drop'=>'match'];$by=[];foreach($all as$q)$by[$q['type']][]=$q;$seed=qz_seed($u,$a,$att);foreach($by as$t=>&$list){qz_shuffle($list,$seed+crc32($t));$list=array_slice($list,0,6);}unset($list);$final=[];foreach($order as$t){$key=$alias[$t]??$t;if(!empty($by[$key])){foreach($by[$key] as$q){$q['block_type']=$t;$final[]=$q;}unset($by[$key]);}}foreach($by as$t=>$list)foreach($list as$q){$q['block_type']=$t;$final[]=$q;}return$final;}
function qz_correct($q,$a){if($a===null||$a==='')return false;if($q['type']==='pronunciation')return !empty($a);if($q['type']==='match'){if(!is_array($a))return false;foreach($q['pairs']as$i=>$p)if(!isset($a[$i])||(string)$a[$i]!== (string)$p['right'])return false;return true;}if($q['type']==='multiple_choice'){if(is_numeric($q['correct']))return(string)$a===(string)$q['correct'];$opts=$q['options'];return isset($opts[(int)$a])&&qz_norm($opts[(int)$a])===qz_norm($q['correct']);}return qz_norm($a)===qz_norm($q['correct']);}
$unitId=isset($_GET['unit'])?intval($_GET['unit']):0;$assignment=isset($_GET['assignment'])?intval($_GET['assignment']):0;$mode=$_GET['mode']??'intro';$qIndex=isset($_GET['q'])?intval($_GET['q']):0;if(!$unitId)die('Missing unit id.');$pdo=get_pdo();$st=$pdo->prepare('SELECT * FROM activities WHERE unit_id=:u ORDER BY id ASC');$st->execute(['u'=>$unitId]);$activities=$st->fetchAll(PDO::FETCH_ASSOC);$all=[];foreach($activities as$act)foreach(qz_normalize_activity($act)as$q)$all[]=$q;if(!$all)die('<div style="font-family:Arial;padding:30px;color:#7c3aed"><h2>No scoreable quiz activities found for this unit.</h2></div>');$attKey='qz_attempt_'.$unitId.'_'.$assignment;if(!isset($_SESSION[$attKey]))$_SESSION[$attKey]=1;$att=(int)$_SESSION[$attKey];$setKey='qz_set_'.$unitId.'_'.$assignment.'_'.$att;$ansKey='qz_answers_'.$unitId.'_'.$assignment.'_'.$att;if(isset($_GET['reset'])){$_SESSION[$attKey]=$att+1;unset($_SESSION[$setKey],$_SESSION[$ansKey]);qz_redirect('intro',$unitId,$assignment);}if(!isset($_SESSION[$setKey]))$_SESSION[$setKey]=qz_build($all,$unitId,$assignment,$att);if(!isset($_SESSION[$ansKey]))$_SESSION[$ansKey]=[];$quiz=$_SESSION[$setKey];$answers=&$_SESSION[$ansKey];$total=count($quiz);
if($_SERVER['REQUEST_METHOD']==='POST'&&$mode==='quiz'){$qIndex=max(0,min($qIndex,$total-1));$q=$quiz[$qIndex];if(isset($_POST['skip'])){$answers[$qIndex]=['answer'=>null,'skipped'=>true,'correct'=>false];$n=$qIndex+1;qz_redirect($n>=$total?'result':'quiz',$unitId,$assignment,$n>=$total?null:$n);} $ans=$q['type']==='match'?(isset($_POST['answer'])&&is_array($_POST['answer'])?$_POST['answer']:[]):($_POST['answer']??'');$ok=qz_correct($q,$ans);$answers[$qIndex]=['answer'=>$ans,'skipped'=>false,'correct'=>$ok];$n=$qIndex+1;qz_redirect($n>=$total?'result':'quiz',$unitId,$assignment,$n>=$total?null:$n);}
$labels=['pronunciation'=>['Pronunciation','Say the phrase','ti-microphone'],'multiple_choice'=>['Multiple choice','Pick the correct answer','ti-checks'],'fill'=>['Fill in the blank','Complete the sentence','ti-pencil'],'match'=>['Match','Connect each word to its pair','ti-arrows-shuffle'],'drag_drop'=>['Drag and drop','Arrange or match items','ti-hand-move'],'unscramble'=>['Unscramble','Write the sentence in order','ti-sort-ascending']];$counts=[];foreach($quiz as$q){$bt=$q['block_type']??$q['type'];$counts[$bt]=($counts[$bt]??0)+1;}$correct=0;$skip=0;foreach($answers as$a){if(!empty($a['correct']))$correct++;if(!empty($a['skipped']))$skip++;}$wrong=max(0,$total-$correct-$skip);$percent=$total?round($correct/$total*100):0;
?><!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Unit Quiz</title><link href="https://fonts.googleapis.com/css2?family=Fredoka:wght@500;600;700&family=Nunito:wght@500;600;700;800;900&display=swap" rel="stylesheet"><link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/@tabler/icons-webfont@latest/tabler-icons.min.css"><style>:root{--pu:#8070dd;--or:#ff7315;--ink:#14113a;--mut:#8f86c5;--line:#e9e3fb;--bg:#f8f7ff}*{box-sizing:border-box}body{margin:0;background:var(--bg);font-family:Nunito,sans-serif;color:var(--ink)}.page{max-width:1020px;margin:auto;padding:34px 24px 56px}.top,.card{background:white;border:1px solid var(--line);border-radius:22px}.top{padding:18px 28px;display:flex;justify-content:space-between;max-width:820px;margin:0 auto 26px}.brand{font-weight:900;color:var(--pu);font-size:20px}.sub{font-size:15px;color:var(--mut)}.tabs{display:flex;gap:10px;justify-content:center;flex-wrap:wrap;margin-bottom:20px}.tab{border:1px solid var(--line);background:white;color:var(--mut);border-radius:999px;padding:9px 16px;font-size:13px;font-weight:900}.tab.on{background:var(--pu);color:white}.screen-title{text-align:center;color:#c0b8e8;font-size:13px;font-weight:900;letter-spacing:.08em;text-transform:uppercase;margin-bottom:14px}.card{max-width:720px;margin:auto;padding:36px}.kicker{display:inline-block;background:#fff0e6;color:var(--or);border:1px solid #ffd1ad;border-radius:999px;padding:7px 16px;font-weight:900;font-size:13px}.title{font:700 40px Fredoka,sans-serif;color:var(--or);margin:14px 0 6px}.lead{color:var(--pu);font-size:18px;line-height:1.45}.chips{display:flex;gap:10px;flex-wrap:wrap;margin:22px 0}.chip{border:1px solid var(--line);border-radius:999px;color:var(--pu);padding:9px 14px;font-size:14px;font-weight:900;background:#fbfaff}.hr{height:1px;background:var(--line);margin:24px 0}.included{color:#a99ee0;font-size:13px;font-weight:900}.type-row{display:flex;gap:14px;align-items:center;background:#f6f3ff;border-radius:15px;padding:16px;margin:10px 0;text-decoration:none;color:inherit}.type-row:hover{outline:2px solid var(--pu)}.type-row i{color:var(--pu);font-size:24px}.type-row b{font-size:16px}.type-row span:last-child{margin-left:auto;color:var(--pu);font-weight:900;font-size:18px}.btn{border:0;border-radius:13px;padding:16px 20px;font-weight:900;cursor:pointer;text-decoration:none;display:inline-flex;align-items:center;justify-content:center;gap:8px;font-size:16px}.btn-primary{background:var(--or);color:white}.btn-purple{background:var(--pu);color:white}.btn-light{background:white;color:var(--pu);border:1px solid var(--line)}.w100{width:100%}.progress-head{display:flex;justify-content:space-between;color:var(--pu);font-size:14px;font-weight:900}.track{height:9px;background:#eeeafa;border-radius:999px;overflow:hidden;margin:10px 0 24px}.bar{height:100%;background:linear-gradient(90deg,var(--or),var(--pu))}.tag{display:inline-flex;gap:8px;align-items:center;background:#f0ecff;color:var(--pu);border-radius:999px;padding:8px 13px;font-size:13px;font-weight:900;text-transform:uppercase;margin-bottom:16px}.question{font-weight:900;line-height:1.4;margin-bottom:22px;font-size:24px}.option{border:1px solid var(--line);border-radius:14px;padding:16px;margin-bottom:12px;display:flex;gap:14px;font-weight:800;font-size:17px}.option input{display:none}.letter{background:#eeeafa;color:var(--pu);border-radius:999px;width:30px;height:30px;display:inline-flex;align-items:center;justify-content:center}.option:has(input:checked){border-color:var(--pu);background:#f8f6ff}.input,.select{width:100%;border:1px solid var(--line);border-radius:13px;padding:16px;font:800 17px Nunito;margin-bottom:12px}.match-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.match-left{padding:15px;border:1px solid var(--pu);border-radius:12px;text-align:center;font-weight:900;background:#fbfaff;font-size:16px}.actions{display:flex;gap:12px;margin-top:18px}.result-hero{background:linear-gradient(135deg,#eee9ff,#fff0e6);border-radius:18px;text-align:center;padding:36px 22px;margin-bottom:22px}.pct{font:700 58px Fredoka,sans-serif;color:var(--or)}.pill{display:inline-flex;border-radius:999px;padding:7px 12px;font-size:14px;font-weight:900;margin:5px}.review{border:1px solid var(--line);border-radius:15px;padding:16px;margin-bottom:12px}.pron-card{min-height:480px;border:1px solid #EDE9FA;border-radius:30px;background:#fff;padding:18px;text-align:center;box-shadow:0 8px 24px rgba(127,119,221,.09)}.pron-listen-cue{display:inline-flex;margin-bottom:12px;padding:6px 13px;border-radius:999px;background:#EEEDFE;color:#534AB7;font-size:12px;font-weight:900}.pron-image{width:100%;height:340px;margin-bottom:14px;border-radius:24px;background:#fff;border:1px solid #EDE9FA;display:flex;align-items:center;justify-content:center;overflow:hidden;padding:10px}.pron-image img{width:100%;height:100%;object-fit:contain;border-radius:18px}.pron-word{font-size:28px;font-weight:900;color:#534AB7}.pron-box{width:100%;margin-top:8px;border-radius:12px;padding:9px 12px;font-size:13px;font-weight:800;text-align:center}.pron-captured{border:1px solid #EDE9FA;background:#fff;color:#534AB7}.pron-actions{display:flex;justify-content:center;gap:10px;flex-wrap:wrap;margin-top:16px;padding-top:16px;border-top:1px solid #F0EEF8}.pron-btn{border:0;border-radius:10px;min-width:130px;padding:13px 20px;color:#fff;font-size:13px;font-weight:900;cursor:pointer}.pron-purple{background:#7F77DD}.pron-orange{background:#F97316}@media(max-width:760px){.page{padding:22px 14px 42px}.top{max-width:100%;padding:14px 18px}.card{max-width:100%;padding:24px}.title{font-size:34px}.question{font-size:20px}.match-grid{grid-template-columns:1fr}.actions{flex-direction:column}.pron-image{height:280px}.pron-actions{display:grid;grid-template-columns:1fr}.pron-btn{width:100%}}</style></head><body><div class="page"><div class="top"><div><div class="brand">Quiz de Unidad</div><div class="sub">inglesdeuna · <?php echo$total;?> preguntas en bloques</div></div></div><div class="tabs"><?php foreach(['intro'=>'Intro','quiz'=>'Quiz','result'=>'Resultado','review'=>'Review']as$m=>$lab):?><button class="tab <?php echo$mode===$m?'on':'';?>"><?php echo qz_h($lab);?></button><?php endforeach;?></div>
<?php if($mode==='intro'):?><div class="screen-title">Pantalla 1 — Portada del quiz</div><div class="card"><span class="kicker">UNIT <?php echo$unitId;?> · QUIZ</span><div class="title">Unit Quiz</div><div class="lead">Choose a block to start there, or press Start quiz to begin from pronunciation.</div><div class="chips"><span class="chip"><?php echo$total;?> questions</span><span class="chip">Max 6 per activity type</span><span class="chip">Skipped = 0</span></div><div class="hr"></div><div class="included">WHAT'S INCLUDED</div><?php foreach($counts as$t=>$c):$inf=$labels[$t]??[$t,'','ti-circle'];$first=0;foreach($quiz as$i=>$qq){if(($qq['block_type']??$qq['type'])===$t){$first=$i;break;}}?><a class="type-row" href="?mode=quiz&q=<?php echo$first;?>&unit=<?php echo$unitId;?>&assignment=<?php echo$assignment;?>"><i class="ti <?php echo qz_h($inf[2]);?>"></i><div><b><?php echo qz_h($inf[0]);?></b><small style="display:block;color:var(--mut)"><?php echo qz_h($inf[1]);?></small></div><span><?php echo$c;?></span></a><?php endforeach;?><div class="hr"></div><a class="btn btn-purple w100" href="?mode=quiz&q=0&unit=<?php echo$unitId;?>&assignment=<?php echo$assignment;?>">Start quiz</a></div>
<?php elseif($mode==='quiz'):$qIndex=max(0,min($qIndex,$total-1));$q=$quiz[$qIndex];$bt=$q['block_type']??$q['type'];$inf=$labels[$bt]??[$bt,'','ti-circle'];?><div class="screen-title">Pregunta <?php echo$qIndex+1;?> de <?php echo$total;?> — <?php echo qz_h($inf[0]);?></div><div class="card"><div class="progress-head"><span>PROGRESS</span><span><?php echo$qIndex+1;?> / <?php echo$total;?></span></div><div class="track"><div class="bar" style="width:<?php echo round((($qIndex+1)/$total)*100);?>%"></div></div><div class="tag"><i class="ti <?php echo qz_h($inf[2]);?>"></i><?php echo qz_h($inf[0]);?></div><?php if($q['type']==='pronunciation'):?><div class="pron-card"><div class="pron-listen-cue">Listen first</div><div class="pron-image"><?php if(!empty($q['image'])):?><img src="<?php echo qz_h($q['image']);?>" alt="<?php echo qz_h($q['correct']);?>"><?php else:?><div class="pron-word"><?php echo qz_h($q['correct']);?></div><?php endif;?></div><?php if(empty($q['image'])):?><div class="pron-word"><?php echo qz_h($q['correct']);?></div><?php endif;?><div class="pron-box pron-captured" id="pron-captured"></div></div><form method="post" id="pron-form"><input type="hidden" name="answer" id="pron-answer" value=""><div class="pron-actions"><button type="button" class="pron-btn pron-purple" id="pron-listen">Listen</button><button type="button" class="pron-btn pron-purple" id="pron-speak">Speaker</button><button class="pron-btn pron-purple" name="skip" value="1">Skip</button></div></form><script>(function(){var expected=<?php echo json_encode((string)$q['correct']);?>;var audio=<?php echo json_encode((string)$q['audio']);?>;var cap=document.getElementById('pron-captured'),answer=document.getElementById('pron-answer'),form=document.getElementById('pron-form'),submitted=false;var currentAudio=null,isSpeaking=false,isPaused=false,utter=null;function norm(t){return String(t||'').toLowerCase().trim().replace(/[.,!?;:'"-]/g,'').replace(/\s+/g,' ')}function overlap(a,b){var wa=a.split(' ').filter(Boolean),wb=b.split(' ').filter(Boolean);if(!wa.length||!wb.length)return 0;var m=wa.filter(function(w){return wb.indexOf(w)!==-1}).length;return m/Math.max(wa.length,wb.length)}function isMatch(a,b){return a===b||overlap(a,b)>=.8}function submit(ok){if(submitted)return;submitted=true;answer.value=ok?'1':'';setTimeout(function(){form.submit()},250)}function label(){var b=document.getElementById('pron-listen');if(b)b.textContent=isPaused?'Resume':(isSpeaking?'Pause':'Listen')}function voice(){var vs=[];try{vs=speechSynthesis.getVoices()||[]}catch(e){};for(var i=0;i<vs.length;i++)if(String(vs[i].lang||'').toLowerCase()==='en-us')return vs[i];for(var j=0;j<vs.length;j++)if(String(vs[j].lang||'').toLowerCase().indexOf('en')===0)return vs[j];return null}function listen(){if(audio){if(!currentAudio){currentAudio=new Audio(audio);currentAudio.onended=function(){isSpeaking=false;isPaused=false;label()}}if(!currentAudio.paused){currentAudio.pause();isSpeaking=true;isPaused=true}else{currentAudio.play();isSpeaking=true;isPaused=false}label();return}if(!window.speechSynthesis)return;if(speechSynthesis.speaking&&!speechSynthesis.paused){speechSynthesis.pause();isSpeaking=true;isPaused=true;label();return}if(speechSynthesis.paused||isPaused){speechSynthesis.resume();isSpeaking=true;isPaused=false;label();return}speechSynthesis.cancel();utter=new SpeechSynthesisUtterance(expected);utter.lang='en-US';utter.rate=.82;utter.pitch=1;var v=voice();if(v)utter.voice=v;utter.onstart=function(){isSpeaking=true;isPaused=false;label()};utter.onend=function(){isSpeaking=false;isPaused=false;label()};speechSynthesis.speak(utter)}function speak(){var C=window.SpeechRecognition||window.webkitSpeechRecognition;if(!C){cap.textContent='Speech recognition is not available in this browser.';submit(false);return}var r=new C();r.lang='en-US';r.interimResults=false;r.maxAlternatives=1;r.continuous=false;cap.textContent='Listening...';r.onresult=function(e){var said=String(e.results&&e.results[0]&&e.results[0][0]?e.results[0][0].transcript:'');var ok=isMatch(norm(said),norm(expected));cap.textContent='You said: '+said;submit(ok)};r.onerror=function(){cap.textContent='Try again.';submit(false)};r.start()}document.getElementById('pron-listen').onclick=listen;document.getElementById('pron-speak').onclick=speak;})();</script><?php elseif($q['type']==='multiple_choice'):?><form method="post"><div class="question"><?php echo qz_h($q['question']);?></div><?php foreach($q['options']as$i=>$op):?><label class="option"><input type="radio" name="answer" value="<?php echo$i;?>" required><span class="letter"><?php echo chr(65+$i);?></span><?php echo qz_h($op);?></label><?php endforeach;?><div class="actions"><button class="btn btn-purple" type="submit">Next</button><button class="btn btn-light" name="skip" value="1">Skip</button></div></form><?php elseif($q['type']==='match'):?><form method="post"><div class="question"><?php echo qz_h($q['question']);?></div><div class="match-grid"><?php $rights=array_column($q['pairs'],'right');foreach($q['pairs']as$i=>$p):?><div class="match-left"><?php echo qz_h($p['left']);?></div><select class="select" name="answer[<?php echo$i;?>]" required><option value="">Choose</option><?php foreach($rights as$r):?><option value="<?php echo qz_h($r);?>"><?php echo qz_h($r);?></option><?php endforeach;?></select><?php endforeach;?></div><div class="actions"><button class="btn btn-purple" type="submit">Next</button><button class="btn btn-light" name="skip" value="1">Skip</button></div></form><?php else:?><form method="post"><div class="question"><?php echo qz_h($q['question']);?></div><input class="input" name="answer" required autocomplete="off" placeholder="Type your answer"><div class="actions"><button class="btn btn-purple" type="submit">Next</button><button class="btn btn-light" name="skip" value="1">Skip</button></div></form><?php endif;?></div>
<?php elseif($mode==='result'):?><div class="screen-title">Resultado</div><div class="card"><div class="result-hero"><div class="pct"><?php echo$percent;?>%</div><div class="lead">Quiz complete</div><span class="pill" style="background:#eafff3;color:#07823f"><?php echo$correct;?> correct</span><span class="pill" style="background:#fff0f0;color:#c82020"><?php echo$wrong;?> wrong</span><span class="pill" style="background:#f0ecff;color:#8070dd"><?php echo$skip;?> skipped</span></div><div class="actions"><a class="btn btn-purple" href="?mode=review&unit=<?php echo$unitId;?>&assignment=<?php echo$assignment;?>">Review</a><a class="btn btn-light" href="?reset=1&unit=<?php echo$unitId;?>&assignment=<?php echo$assignment;?>">Try again</a></div></div><?php elseif($mode==='review'):?><div class="screen-title">Review</div><div class="card"><?php foreach($quiz as$i=>$q):$a=$answers[$i]??null;?><div class="review"><b><?php echo$i+1;?>. <?php echo qz_h($q['question']);?></b><br><small><?php echo!empty($a['correct'])?'Correct':'0 points';?></small></div><?php endforeach;?></div><?php endif;?></div></body></html>